    public String[] getUserName(String cuid, String token){
        String[] userName = new String[]{"",""};
        HttpClient httpClient = HttpClientBuilder.create().build();
        String url = "https://graph.facebook.com/"+cuid.substring(3)+"?fields=first_name,last_name&access_token="+token;
        HttpGet httpGet = new HttpGet(url);
        try {
            HttpResponse httpResoponse = httpClient.execute(httpGet);
            if(HttpStatus.SC_OK == httpResoponse.getStatusLine().getStatusCode()){
                HttpEntity httpEntity = httpResoponse.getEntity();
                if(httpEntity != null && httpEntity.getContent() != null && httpEntity.getContentLength() > 0){
                    String responseJson = EntityUtils.toString(httpEntity,"UTF-8");
                    JSONObject obj = new JSONObject(responseJson);
                    userName[0]=obj.optString("first_name");
                    userName[1]=obj.optString("last_name");
                    EntityUtils.consumeQuietly(httpEntity);
                }
            }
        }
        catch (Exception e){
            System.out.println(e.getMessage());
        }
        return userName;
    }

