  public JSONObject urlJSONCall(String urlstring,JSONObject jo){
    HttpsURLConnection connection;
    try {

      URL url=new URL(urlstring);
      connection = (HttpsURLConnection) url.openConnection();
      connection.setConnectTimeout(60000);//60 seconds
      connection.setReadTimeout(60000);//60 seconds
      connection.setDoOutput(true);
      connection.setDoInput(true);
      connection.setRequestMethod("POST");
      connection.setChunkedStreamingMode(0);
      connection.setRequestProperty("Content-Type", "application/json");

      //write the request
      OutputStreamWriter out = new OutputStreamWriter(connection.getOutputStream());
      //write the request parameters
      out.write(jo.toString());
      //flush the output buffer
      out.flush();

      //get result
      StringWriter sw=new StringWriter();

      BufferedInputStream br;
      boolean success=false;
      if(connection.getResponseCode()<=201){//200 OK, 201 CREATED
        success=true;
        br=new BufferedInputStream(connection.getInputStream());
      }
      else{
        br=new BufferedInputStream(connection.getErrorStream());
      }

      int c;
      while((c = br.read())!=-1){
        sw.write(c);
      }

//      new Log("fb.txt").log("Result:\n"+sw.toString()+"\n");
      return new JSONObject(sw.toString());

    }
    catch (MalformedURLException e) {
      ExceptionManager.getInstance().processException(e);
    }
    catch (UnsupportedEncodingException e) {
      ExceptionManager.getInstance().processException(e);
    }
    catch (IOException e) {
      ExceptionManager.getInstance().processException(e);
    } catch (JSONException e) {
      ExceptionManager.getInstance().processException(e);
    }
    return null;
  }

